export type MajorChangeArtifactType = 'document' | 'presentation' | 'spreadsheet';

export type MajorChangeCaseCategory =
  | 'create'
  | 'content-edit'
  | 'style-edit'
  | 'theme-change'
  | 'structural-edit'
  | 'large-rewrite'
  | 'validation-export'
  | 'runtime-plan'
  | 'viewport'
  | 'formula-change'
  | 'query-change'
  | 'schema-layout'
  | 'dependency-refresh'
  | 'performance-sensitive';

export type MajorChangeCasePriority = 'required' | 'extended';

export interface MajorChangeCaseDefinition {
  id: string;
  artifactType: MajorChangeArtifactType;
  category: MajorChangeCaseCategory;
  title: string;
  prompt: string;
  startingState: string;
  expectedOutcome: string;
  checks: string[];
  priority: MajorChangeCasePriority;
}

